### 3.3 TaskRender (Computed)

The TaskRender interface is computed at runtime for canvas rendering. It is NEVER persisted.

#### 3.3.1 Render Interface

```typescript
/**
 * Color mapping for task types.
 * Used for InstancedMesh color attributes.
 */
export type TaskColor = 'blue' | 'orange' | 'gray';

/**
 * Color mapping constant.
 */
export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
  maintenance: 'blue',
  overhaul: 'orange',
  inspection: 'gray',
};

/**
 * TaskRender - computed values for canvas rendering.
 *
 * This interface contains position and dimension data
 * calculated from the persistent Task entity.
 * NEVER persisted - recomputed on data load.
 */
export interface TaskRender {
  /** Same as Task.id for cross-reference */
  id: string;

  /**
   * Y position as 0-based index in trains array.
   * Computed from Task.trainId via lookup map.
   * World Y = trainIndex * PX_PER_TRAIN (negated for downward growth)
   */
  trainIndex: number;

  /**
   * X position as days since dataset start date.
   * Computed: daysBetween(meta.startDate, task.startDate)
   * World X = startDay * PX_PER_DAY
   */
  startDay: number;

  /**
   * Width in days.
   * Computed: daysBetween(task.startDate, task.endDate)
   * World Width = duration * PX_PER_DAY
   */
  duration: number;

  /**
   * Color derived from Task.type.
   * Used for InstancedMesh color attribute.
   */
  color: TaskColor;

  /** Passthrough from Task.hasConflict */
  hasConflict: boolean;

  /** Passthrough from Task.type for label display */
  type: TaskType;

  /** Optional: predecessor ID for dependency lines */
  predecessorId?: string;
}
```

#### 3.3.2 Transform Function

```typescript
/**
 * Transform persistent Task to render-ready TaskRender.
 *
 * @param task - Persistent task entity
 * @param trainIndexMap - Map of trainId to array index
 * @param datasetStartDate - Dataset start date string (ISO 8601)
 * @returns TaskRender for canvas rendering
 */
function transformToRender(
  task: Task,
  trainIndexMap: Map<string, number>,
  datasetStartDate: string
): TaskRender {
  const trainIndex = trainIndexMap.get(task.trainId);
  if (trainIndex === undefined) {
    throw new Error(`Train not found: ${task.trainId}`);
  }

  const startDay = daysBetween(datasetStartDate, task.startDate);
  const duration = daysBetween(task.startDate, task.endDate);

  return {
    id: task.id,
    trainIndex,
    startDay,
    duration,
    color: TYPE_TO_COLOR[task.type],
    hasConflict: task.hasConflict,
    type: task.type,
    predecessorId: task.predecessorId,
  };
}
```

